// CLV ve churn risk hesaplaması
const customers = $input.all();

const result = customers.map(({ json }) => {
  // Churn risk faktörleri
  const daysSinceOrder = json.days_since_order || 0;
  const daysSinceEmail = json.days_since_email || 999;
  const emailOpenRate = json.email_open_rate || 0;
  const totalOrders = json.total_orders || 0;

  // Risk skoru (0-100)
  let riskScore = 0;

  // Recency (max 40 puan)
  if (daysSinceOrder > 120) riskScore += 40;
  else if (daysSinceOrder > 90) riskScore += 30;
  else if (daysSinceOrder > 60) riskScore += 20;
  else if (daysSinceOrder > 30) riskScore += 10;

  // Engagement (max 30 puan)
  if (emailOpenRate < 0.1) riskScore += 30;
  else if (emailOpenRate < 0.3) riskScore += 20;
  else if (emailOpenRate < 0.5) riskScore += 10;

  // Frequency (max 30 puan - düşük frequency artırır risk)
  if (totalOrders <= 1) riskScore += 30;
  else if (totalOrders <= 3) riskScore += 20;
  else if (totalOrders <= 5) riskScore += 10;

  // CLV tahmini (basit)
  const avgOrderValue = json.avg_order_value || json.total_spent / Math.max(json.total_orders, 1);
  const expectedFutureOrders = Math.max(0, 12 - daysSinceOrder / 30); // 12 ay içinde beklenen sipariş
  const estimatedCLV = avgOrderValue * expectedFutureOrders * 0.3; // %30 marj

  // Risk seviyesi
  let riskLevel = 'LOW';
  if (riskScore >= 70) riskLevel = 'HIGH';
  else if (riskScore >= 40) riskLevel = 'MEDIUM';

  // Önerilen aksiyon
  let recommendedAction = 'WATCH';
  if (riskScore >= 80) recommendedAction = 'IMMEDIATE_WINBACK';
  else if (riskScore >= 60) recommendedAction = 'WINBACK_CAMPAIGN';
  else if (riskScore >= 40) recommendedAction = 'REENGAGEMENT';

  return {
    json: {
      customerId: json.customer_id,
      email: json.email,
      firstName: json.first_name,
      daysSinceOrder,
      totalOrders: json.total_orders,
      totalSpent: json.total_spent,
      emailOpenRate,
      riskScore: Math.min(100, riskScore),
      riskLevel,
      estimatedCLV: Math.round(estimatedCLV),
      recommendedAction
    }
  };
});

// Yüksek risklileri filtrele
 return result.filter(r => r.json.riskScore >= 40).map(r => r);

